def retry_call(fn, attempts: int = 3, delay: float = 0.1):
    last_error = None
    for attempt in range(attempts):
        try:
            return fn()
        except Exception as exc:
            last_error = exc
            if attempt + 1 < attempts:
                time.sleep(delay * (2 ** attempt))
    raise last_error
