from collections import deque

class TaskQueue:
    def __init__(self):
        self._items = deque()

    def push(self, item: object) -> None:
        self._items.append(item)

    def pop(self) -> object:
        if not self._items:
            raise IndexError("queue is empty")
        return self._items.popleft()
```

